        	Regex regex = new Regex(@"\d+");
        	Match match;
        	int indexofProdStructure = varTextofAC.LastIndexOf(":");
        	string ProdStructureNo = varTextofAC.Substring(indexofProdStructure + 2);
        	int len = ProdStructureNo.Length;
        	ProdStructureNo = ProdStructureNo.Substring(0,len - 2);
        	match = regex.Match(ProdStructureNo);
        	if (match.Success)
        	{
        		ProdStructNum = match.Value;
        		Ranorex.Report.Log(ReportLevel.Info, "Product Structure Number Created In PLM: " + ProdStructNum);
        	}
        	
        	else
        	{
        		Ranorex.Validate.Fail("Did not find an item number");
        	}
        }

